+  exit 0
+fi
+if [ "$1" = "-m" ] && [ "$2" = "pip" ] && [ "$3" = "--version" ]; then
+  if [ "${DTWIZ_TEST_FAIL_PIP:-0}" = "1" ]; then
+    echo "pip unavailable" >&2
+    exit 1
+  fi
+  echo "pip 24.0 from /tmp/site-packages/pip"
+  exit 0
+fi
+if [ "$1" = "-m" ] && [ "$2" = "venv" ] && [ "$3" = "--help" ]; then
+  if [ "${DTWIZ_TEST_FAIL_VENV:-0}" = "1" ]; then
